import{_ as e,c as o,o as t,a}from"./app.ee2751a3.js";const g=JSON.parse('{"title":"Large model","description":"","frontmatter":{},"headers":[{"level":2,"title":"Train models","slug":"train-models"},{"level":2,"title":"Fine-tune the models","slug":"fine-tune-the-models"},{"level":2,"title":"Publish models","slug":"publish-models"}],"relativePath":"docs/lg/index.md"}'),i={name:"docs/lg/index.md"},n=a('<h1 id="large-model" tabindex="-1">Large model <a class="header-anchor" href="#large-model" aria-hidden="true">#</a></h1><p><a rel="license" href="https://creativecommons.org/licenses/by-nc-sa/4.0/"><img alt="Creative Commons License" style="border-width:0;" src="https://i.creativecommons.org/l/by-nc-sa/4.0/88x31.png"></a></p><p>The model builds on the <a href="https://github.com/UniversalDependencies/UD_Hungarian-Szeged" target="_blank" rel="noopener noreferrer">Hungarian UD treebank</a> and the <a href="https://github.com/UniversalDependencies/UD_Hungarian-Szeged" target="_blank" rel="noopener noreferrer">NerKor corpus</a>, thus it is capable of predicting PoS and morphological tags, computing lemmata, providing dependency parses of sentences and marking named entities.</p><h2 id="train-models" tabindex="-1">Train models <a class="header-anchor" href="#train-models" aria-hidden="true">#</a></h2><ol><li>Install dependencies: <code>poetry install</code> To enable GPU support you need to install <code>cupy</code> and <code>torch</code>. For CUDA 11.1 issue: <ul><li><code>poetry run python -m pip install cupy-cuda111</code></li><li><code>poetry run python -m pip install torch==1.9.0+cu111 -f https://download.pytorch.org/whl/torch_stable.html</code></li></ul></li><li>Activate the virtual environment <code>poetry shell</code></li><li>Fetch datafiles: <code>spacy project assets -S</code> <br> (<code>-S</code> won&#39;t retry fetch resources if they are already present)</li><li>Build all the models: <code>spacy project run all</code></li></ol><h2 id="fine-tune-the-models" tabindex="-1">Fine-tune the models <a class="header-anchor" href="#fine-tune-the-models" aria-hidden="true">#</a></h2><p>Hyperparameters of the underlying models can be fine-tuned using Weights&amp;Biases: <code>wandb sweep</code> with one of the <code>sweep_*.yml</code> config file.</p><h2 id="publish-models" tabindex="-1">Publish models <a class="header-anchor" href="#publish-models" aria-hidden="true">#</a></h2><ol><li>Make sure dependencies are up-to-date: <code>poetry update</code></li><li>Bump version: <code>bumpversion patch</code> / <code>minor</code> / <code>major</code></li><li>Build the model as described in the previous section</li><li>Publish the new model to Hugging Face Hub: <code>python -m spacy project run publish</code> (must be executed in the model&#39;s directory)</li></ol>',9),l=[n];function r(d,s,c,h,p,u){return t(),o("div",null,l)}var _=e(i,[["render",r]]);export{g as __pageData,_ as default};
